const todayLabel = new Intl.DateTimeFormat("en-CA", { weekday: "long", month: "long", day: "numeric" }).format(new Date());
const initialProgress: ProgressState = { xp: 0, stars: 0, coins: 25, streak: 0, completed: [], mastery: { math: 0, english: 0 }, attempts: {}, diagnosticComplete: false, diagnosticScore: 0, lastActivity: "", badges: [] };
const initialSettings: Settings = { breaks: true, dailyLimit: 90, subjects: "all" };

const q = (prompt: string, hint: string, options: string[], answer: number, explanation: string): Question => ({ prompt, hint, options, answer, explanation });
function getGradeLabel(grade: Grade) { return `Grade ${grade}`; }

const gradeThreeProgram = getProgram(3);

const diagnosticQuestions: Question[] = [
  q("What is 46 + 27?", "Add ones, then tens.", ["63", "73", "83", "67"], 1, "46 + 27 = 73."),
  q("Which number has 5 hundreds, 0 tens and 8 ones?", "Use the place-value positions.", ["580", "508", "58", "805"], 1, "5 hundreds, 0 tens and 8 ones makes 508."),
  q("What is 3 × 4?", "Count 3 groups of 4.", ["7", "8", "12", "16"], 2, "3 groups of 4 equals 12."),
  q("Which fraction shows one part out of three equal parts?", "The numerator is the parts you have.", ["3/1", "1/2", "1/3", "2/3"], 2, "1/3 means one of three equal parts."),
  q("What is the main idea of a text?", "It is the big message.", ["The smallest detail", "The main message", "The title only", "A random guess"], 1, "The main idea is the important message the text communicates."),
  q("Which sentence is written correctly?", "Check capital letter and punctuation.", ["my dog runs.", "My dog runs.", "my dog runs", "My dog runs"], 1, "A sentence needs a capital letter and punctuation."),
  q("Which word is a verb?", "A verb can show an action.", ["bright", "jump", "pencil", "happily"], 1, "Jump is an action word."),
  q("A path is covered in puddles. What can you infer?", "Use the clue to make a reasonable idea.", ["It probably rained.", "It was a drought.", "The path was indoors.", "Nobody saw it."], 0, "Puddles suggest rain likely fell."),
];

